import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useSocket } from '../../context/SocketContext';
import { getTheme, cardStyle } from '../../utils/theme';
import { PageHeader, Btn } from '../../components/common/UI';
import API from '../../utils/api';

const ICE_SERVERS = {
  iceServers: [
    { urls: 'stun:stun.l.google.com:19302' },
    { urls: 'stun:stun1.l.google.com:19302' },
  ],
};

export default function PatientVideoCall() {
  const { user, darkMode } = useAuth();
  const { socket } = useSocket();
  const t = getTheme(darkMode);

  const [phase, setPhase] = useState('lobby');
  const [muted, setMuted] = useState(false);
  const [videoOff, setVideoOff] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [roomId, setRoomId] = useState(null);
  const [peerConnected, setPeerConnected] = useState(false);
  const [statusMsg, setStatusMsg] = useState('');
  const [localStreamReady, setLocalStreamReady] = useState(false);

  // Refs
  const localVideoRef = useRef(null);
  const remoteVideoRef = useRef(null);
  const localStreamRef = useRef(null);
  const pcRef = useRef(null);
  const timerRef = useRef(null);

  const fmt = (s) => `${String(Math.floor(s / 60)).padStart(2, '0')}:${String(s % 60).padStart(2, '0')}`;

  // ── Initialize Local Video (SEPARATE FUNCTION) ──────────────────────────────
  const initLocalVideo = async () => {
    try {
      console.log('1. Requesting camera...');
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { width: { ideal: 1280 }, height: { ideal: 720 } }, 
        audio: true 
      });

      console.log('2. Got stream, tracks:', stream.getTracks().length);
      localStreamRef.current = stream;

      // Enable all tracks
      stream.getTracks().forEach(track => {
        track.enabled = true;
        console.log(`Track ${track.kind}: enabled=${track.enabled}`);
      });

      // Attach to video element
      if (localVideoRef.current) {
        console.log('3. Attaching to video element');
        localVideoRef.current.srcObject = stream;
        localVideoRef.current.muted = true;

        // Wait for metadata to load then play
        localVideoRef.current.onloadedmetadata = () => {
          console.log('4. Metadata loaded, playing...');
          localVideoRef.current.play()
            .then(() => {
              console.log('5. Video playing successfully!');
              setLocalStreamReady(true);
            })
            .catch(err => console.error('Play error:', err));
        };
      }

      return stream;
    } catch (err) {
      console.error('Camera error:', err);
      alert('Cannot access camera: ' + err.message);
      return null;
    }
  };

  // ── Create Peer Connection ─────────────────────────────────────────────────
  const createPeerConnection = useCallback((stream) => {
    console.log('Creating peer connection');
    const pc = new RTCPeerConnection(ICE_SERVERS);

    // Add local tracks
    stream.getTracks().forEach(track => {
      console.log(`Adding track: ${track.kind}`);
      pc.addTrack(track, stream);
    });

    // Handle ICE candidates
    pc.onicecandidate = (event) => {
      if (event.candidate && socket && roomId) {
        socket.emit('webrtc:ice-candidate', { roomId, candidate: event.candidate });
      }
    };

    // Handle remote stream
    pc.ontrack = (event) => {
      console.log('Received remote track');
      if (remoteVideoRef.current && event.streams[0]) {
        remoteVideoRef.current.srcObject = event.streams[0];
        setPeerConnected(true);
        setStatusMsg('Doctor connected');
      }
    };

    pc.onconnectionstatechange = () => {
      console.log('Connection state:', pc.connectionState);
      if (pc.connectionState === 'connected') {
        setStatusMsg('Call connected');
      } else if (pc.connectionState === 'disconnected') {
        setStatusMsg('Connection lost');
        setPeerConnected(false);
      }
    };

    return pc;
  }, [socket, roomId]);

  // ── Start Call ─────────────────────────────────────────────────────────────
  const startCall = async () => {
    setStatusMsg('Starting call...');

    // 1. Get camera
    const stream = await initLocalVideo();
    if (!stream) return;

    // 2. Create room
    setStatusMsg('Creating room...');
    const { data } = await API.post('/webrtc/room');
    const newRoomId = data.roomId;
    setRoomId(newRoomId);
    console.log('Room created:', newRoomId);

    // 3. Create peer connection
    const pc = createPeerConnection(stream);
    pcRef.current = pc;

    // 4. Join signaling room
    if (socket) {
      socket.emit('webrtc:join', { roomId: newRoomId, userId: user._id, role: 'patient' });
    }

    setPhase('in-call');
    setStatusMsg(`Room ready! Share ID: ${newRoomId}`);

    // Start timer
    timerRef.current = setInterval(() => setElapsed(e => e + 1), 1000);
  };

  // ── Join Room ──────────────────────────────────────────────────────────────
  const joinRoom = async (rid) => {
    const stream = await initLocalVideo();
    if (!stream) return;

    const pc = createPeerConnection(stream);
    pcRef.current = pc;

    setRoomId(rid);
    if (socket) {
      socket.emit('webrtc:join', { roomId: rid, userId: user._id, role: 'patient' });
    }

    setPhase('in-call');
    timerRef.current = setInterval(() => setElapsed(e => e + 1), 1000);
  };

  // ── Socket Events ──────────────────────────────────────────────────────────
  useEffect(() => {
    if (!socket || !roomId) return;

    const handleOffer = async ({ offer }) => {
      if (!pcRef.current) return;
      await pcRef.current.setRemoteDescription(new RTCSessionDescription(offer));
      const answer = await pcRef.current.createAnswer();
      await pcRef.current.setLocalDescription(answer);
      socket.emit('webrtc:answer', { roomId, answer });
    };

    const handleAnswer = async ({ answer }) => {
      if (!pcRef.current) return;
      await pcRef.current.setRemoteDescription(new RTCSessionDescription(answer));
    };

    const handleIceCandidate = async ({ candidate }) => {
      if (!pcRef.current) return;
      try {
        await pcRef.current.addIceCandidate(new RTCIceCandidate(candidate));
      } catch (e) {}
    };

    const handlePeerJoined = async () => {
      if (pcRef.current && pcRef.current.signalingState === 'stable') {
        const offer = await pcRef.current.createOffer();
        await pcRef.current.setLocalDescription(offer);
        socket.emit('webrtc:offer', { roomId, offer });
      }
    };

    socket.on('webrtc:offer', handleOffer);
    socket.on('webrtc:answer', handleAnswer);
    socket.on('webrtc:ice-candidate', handleIceCandidate);
    socket.on('webrtc:peer-joined', handlePeerJoined);
    socket.on('webrtc:peer-left', () => {
      setPeerConnected(false);
      if (remoteVideoRef.current) remoteVideoRef.current.srcObject = null;
    });

    return () => {
      socket.off('webrtc:offer');
      socket.off('webrtc:answer');
      socket.off('webrtc:ice-candidate');
      socket.off('webrtc:peer-joined');
      socket.off('webrtc:peer-left');
    };
  }, [socket, roomId]);

  // ── End Call ───────────────────────────────────────────────────────────────
  const endCall = () => {
    localStreamRef.current?.getTracks().forEach(t => t.stop());
    pcRef.current?.close();
    if (socket && roomId) socket.emit('webrtc:leave', { roomId });
    if (timerRef.current) clearInterval(timerRef.current);
    pcRef.current = null;
    setPhase('ended');
    setMuted(false);
    setVideoOff(false);
    setElapsed(0);
    setPeerConnected(false);
    setLocalStreamReady(false);
  };

  const toggleMute = () => {
    const newState = !muted;
    localStreamRef.current?.getAudioTracks().forEach(t => t.enabled = !newState);
    setMuted(newState);
  };

  const toggleVideo = () => {
    const newState = !videoOff;
    localStreamRef.current?.getVideoTracks().forEach(t => t.enabled = !newState);
    setVideoOff(newState);
  };

  useEffect(() => {
    return () => endCall();
  }, []);

  return (
    <div style={{ background: t.bg, minHeight: '100vh', padding: 24 }}>
      <div style={{ maxWidth: 960, margin: '0 auto' }}>
        <PageHeader title="🎥 Video Consultation" darkMode={darkMode} />

        {/* LOBBY */}
        {phase === 'lobby' && (
          <div style={{ ...cardStyle(t), padding: 48, textAlign: 'center' }}>
            <div style={{ fontSize: '5rem', marginBottom: 20 }}>🎥</div>
            <h2 style={{ color: t.text }}>Video Consultation</h2>
            <div style={{ display: 'flex', gap: 16, justifyContent: 'center', marginTop: 24 }}>
              <Btn variant="primary" onClick={startCall}>Start New Call</Btn>
              <Btn variant="outline" onClick={() => {
                const rid = prompt('Enter Room ID:');
                if (rid) joinRoom(rid);
              }}>Join with ID</Btn>
            </div>
          </div>
        )}

        {/* IN CALL */}
        {phase === 'in-call' && (
          <div style={{ ...cardStyle(t), overflow: 'hidden' }}>
            {/* Status */}
            <div style={{ padding: 12, background: peerConnected ? '#10b98120' : '#f59e0b20', textAlign: 'center', fontSize: 13 }}>
              {statusMsg || (peerConnected ? 'Connected' : 'Waiting for doctor...')}
            </div>

            {/* Room ID */}
            {roomId && (
              <div style={{ padding: 12, textAlign: 'center', borderBottom: `1px solid ${t.cardBorder}` }}>
                <code style={{ background: darkMode ? '#1e293b' : '#e2e8f0', padding: '6px 12px', borderRadius: 6 }}>{roomId}</code>
                <button onClick={() => navigator.clipboard.writeText(roomId)} style={{ marginLeft: 12, padding: '4px 12px', cursor: 'pointer' }}>Copy</button>
              </div>
            )}

            {/* Videos - SIMPLE LAYOUT */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 4, background: '#0f172a', minHeight: 400 }}>
              {/* Local Video */}
              <div style={{ position: 'relative', background: '#1e293b', minHeight: 300 }}>
                <video
                  ref={localVideoRef}
                  autoPlay
                  playsInline
                  muted
                  style={{
                    width: '100%',
                    height: '100%',
                    objectFit: 'cover',
                    transform: 'scaleX(-1)',
                    display: videoOff ? 'none' : 'block',
                    background: '#000'
                  }}
                />
                {!localStreamReady && !videoOff && (
                  <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', color: 'white' }}>
                    Loading camera...
                  </div>
                )}
                {videoOff && (
                  <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', color: 'white', textAlign: 'center' }}>
                    <div>📷</div>
                    <div>Camera off</div>
                  </div>
                )}
                <div style={{ position: 'absolute', bottom: 10, left: 10, background: 'rgba(0,0,0,0.6)', color: 'white', padding: '4px 8px', borderRadius: 4, fontSize: 12 }}>
                  You {muted && '🔇'}
                </div>
              </div>

              {/* Remote Video */}
              <div style={{ position: 'relative', background: '#0f172a', minHeight: 300 }}>
                <video
                  ref={remoteVideoRef}
                  autoPlay
                  playsInline
                  style={{
                    width: '100%',
                    height: '100%',
                    objectFit: 'cover',
                    display: peerConnected ? 'block' : 'none',
                    background: '#000'
                  }}
                />
                {!peerConnected && (
                  <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', color: 'white', textAlign: 'center' }}>
                    <div style={{ fontSize: 48 }}>👨‍⚕️</div>
                    <div>Waiting for doctor...</div>
                    <div style={{ width: 30, height: 30, border: '3px solid #0ea5e9', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '10px auto' }} />
                  </div>
                )}
                {peerConnected && (
                  <div style={{ position: 'absolute', bottom: 10, left: 10, background: 'rgba(0,0,0,0.6)', color: 'white', padding: '4px 8px', borderRadius: 4, fontSize: 12 }}>
                    Doctor
                  </div>
                )}
              </div>
            </div>

            {/* Controls */}
            <div style={{ background: '#1e293b', padding: 16, display: 'flex', justifyContent: 'center', gap: 16 }}>
              <button onClick={toggleMute} style={{ width: 48, height: 48, borderRadius: '50%', border: 'none', background: muted ? '#ef4444' : '#334155', color: 'white', cursor: 'pointer', fontSize: 20 }}>
                {muted ? '🔇' : '🎙️'}
              </button>
              <button onClick={toggleVideo} style={{ width: 48, height: 48, borderRadius: '50%', border: 'none', background: videoOff ? '#ef4444' : '#334155', color: 'white', cursor: 'pointer', fontSize: 20 }}>
                {videoOff ? '📷' : '🎥'}
              </button>
              <button onClick={endCall} style={{ padding: '0 24px', height: 48, borderRadius: 24, border: 'none', background: '#ef4444', color: 'white', cursor: 'pointer', fontWeight: 'bold' }}>
                End Call
              </button>
              <div style={{ color: '#94a3b8', display: 'flex', alignItems: 'center' }}>⏱️ {fmt(elapsed)}</div>
            </div>
          </div>
        )}

        {/* ENDED */}
        {phase === 'ended' && (
          <div style={{ ...cardStyle(t), padding: 48, textAlign: 'center' }}>
            <h2>Call Ended</h2>
            <p>Duration: {fmt(elapsed)}</p>
            <Btn variant="primary" onClick={() => setPhase('lobby')}>New Call</Btn>
          </div>
        )}

        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    </div>
  );
}
